import { notFound } from "next/navigation";
import { getTranslations } from "next-intl/server";

import { ExtHero } from "@/components/extension/ext-hero";
import { ExtMetadataPanel } from "@/components/extension/ext-metadata-panel";
import { MarkdownContent } from "@/components/markdown";
import { Link } from "@/lib/i18n/navigation";
import { getExtensionBySlug } from "@/lib/db/queries/extensions";
import type { Locale } from "@/types";

export default async function ExtensionDetailPage({
  params,
}: {
  params: Promise<{ locale: string; slug: string }>;
}) {
  const { locale, slug } = await params;
  const [ext, t] = await Promise.all([
    getExtensionBySlug(slug),
    getTranslations("extensions"),
  ]);
  if (!ext) notFound();

  return (
    <div className="px-7 py-5">
      <nav className="text-muted-foreground mb-4 flex items-center gap-1 text-[12px]">
        <Link href="/extensions" className="hover:text-foreground transition">
          {t("breadcrumb")}
        </Link>
        <span className="opacity-50">/</span>
        <span className="text-foreground">
          {locale === "zh" && ext.nameZh ? ext.nameZh : ext.name}
        </span>
      </nav>

      <ExtHero ext={ext} locale={locale as Locale} />

      <div className="mt-7 grid gap-10 lg:grid-cols-[1fr_280px]">
        <main className="min-w-0">
          {ext.readmeMd ? (
            <MarkdownContent>{ext.readmeMd}</MarkdownContent>
          ) : (
            <p className="text-muted-foreground py-12 text-center text-[13px]">
              {t("noReadme")}
            </p>
          )}

          <section className="border-border mt-10 border-t pt-6">
            <h2 className="serif mb-3 text-xl tracking-tight">
              {t("versionsTitle")}
            </h2>
            <p className="text-muted-foreground text-[13px]">
              {t("noVersions")}
            </p>
          </section>
        </main>

        <ExtMetadataPanel ext={ext} locale={locale as Locale} />
      </div>
    </div>
  );
}

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: string; slug: string }>;
}) {
  const { locale, slug } = await params;
  const ext = await getExtensionBySlug(slug);
  if (!ext) return { title: "Not found · AgentCenter" };
  const name = locale === "zh" && ext.nameZh ? ext.nameZh : ext.name;
  return {
    title: `${name} · AgentCenter`,
    description: ext.tagline ?? ext.description ?? undefined,
  };
}

// ─── Detail Page ────────────────────────────────────────────────────────────
function DetailPage({ ext, lang, t, theme, isDark, cardRadius, cardGap, density, installed, saved, activeTab, setActiveTab, onBack, onInstall, onAdd, onOpenExt, onTagClick, allExtensions }) {
  const isInstalled = installed.has(ext.id);
  const isSaved = saved.has(ext.id);
  const [copied, setCopied] = React.useState(false);

  const formatNum = (n) => n >= 1000 ? `${(n/1000).toFixed(n >= 100000 ? 0 : 1)}k` : n;
  const installCmd = `agent install ${ext.author}/${ext.name.toLowerCase().replace(/\s+/g,'-')}`;
  const copyCmd = () => {
    navigator.clipboard?.writeText(installCmd);
    setCopied(true);
    setTimeout(() => setCopied(false), 1400);
  };

  // Mock metadata
  const meta = {
    version: "2.4.1",
    updated: "3 days ago",
    updatedZh: "3 天前",
    size: "184 KB",
    license: "MIT",
    homepage: `https://${ext.author}.com`,
    repo: `github.com/${ext.author}/${ext.name.toLowerCase().replace(/\s+/g,'-')}`,
    requirements: ext.category === "mcp" ? ["MCP-compatible client", "Node.js ≥ 18"] : ext.category === "skills" ? ["Claude Pro / Team / Enterprise"] : ext.category === "slash" ? ["Claude Desktop ≥ 1.2"] : ["Agent runtime ≥ 0.9"],
    requirementsZh: ext.category === "mcp" ? ["MCP 兼容客户端", "Node.js ≥ 18"] : ext.category === "skills" ? ["Claude Pro / Team / Enterprise"] : ext.category === "slash" ? ["Claude 桌面端 ≥ 1.2"] : ["代理运行时 ≥ 0.9"],
    permissions: [
      { key:"network", label:t.detail_perm_network, granted:true },
      { key:"data",    label:t.detail_perm_data,    granted:true },
      { key:"files",   label:t.detail_perm_files,   granted: ext.category === "skills" || ext.category === "plugins" },
      { key:"runtime", label:t.detail_perm_runtime, granted: ext.id === 2 || ext.id === 12 },
    ],
    features: lang === "zh" ? [
      "开箱即用，无需复杂配置",
      "完整的类型定义和 IDE 智能提示",
      "细粒度权限控制",
      "全面的错误处理和重试机制",
      "可观测性钩子用于审计与调试",
    ] : [
      "Zero-config installation, works out of the box",
      "Complete TypeScript definitions with IDE autocomplete",
      "Fine-grained permission controls",
      "Comprehensive error handling and retry logic",
      "Observability hooks for auditing and debugging",
    ],
    examplePrompt: lang === "zh"
      ? `请使用 ${ext.nameZh} 帮我搜索关于"AI Agent 安全实践"的最新资料并整理成提纲。`
      : `Use ${ext.name} to find the latest research on AI agent security practices and outline it for me.`,
    changelog: [
      { ver:"2.4.1", date:"2026-05-04", note: lang==="zh" ? "修复深色模式下的字体渲染问题" : "Fix font rendering issue in dark mode" },
      { ver:"2.4.0", date:"2026-04-22", note: lang==="zh" ? "新增流式输出支持，性能提升 3×" : "Added streaming output support, 3× faster" },
      { ver:"2.3.0", date:"2026-03-30", note: lang==="zh" ? "重构权限模型，支持企业级 SSO" : "Refactored permissions model, enterprise SSO" },
      { ver:"2.2.0", date:"2026-03-08", note: lang==="zh" ? "添加 12 种新语言支持" : "Added support for 12 new languages" },
    ],
    reviews: [
      { author:"alex.chen", rating:5, date: lang==="zh" ? "1 周前" : "1 week ago", text: lang==="zh" ? "工作流提速明显，团队全员都在用。文档详尽，集成顺畅。" : "Massive workflow speedup, our whole team uses it. Docs are excellent, integration was painless." },
      { author:"priya.k",   rating:5, date: lang==="zh" ? "2 周前" : "2 weeks ago", text: lang==="zh" ? "这是我用过最干净的实现。权限粒度恰到好处，企业部署也很顺利。" : "Cleanest implementation I've used. Permissions are well-scoped and the enterprise rollout was smooth." },
      { author:"m.tanaka",  rating:4, date: lang==="zh" ? "3 周前" : "3 weeks ago", text: lang==="zh" ? "总体很棒，希望未来增加自定义模板功能。" : "Great overall — would love custom template support in a future release." },
    ],
  };

  // Related extensions: same category, exclude self, top 4 by downloads
  const related = allExtensions
    .filter(x => x.id !== ext.id && (x.category === ext.category || (ext.tags && x.tags && ext.tags.some(tt => x.tags.includes(tt)))))
    .sort((a,b) => b.downloads - a.downloads)
    .slice(0, 4);

  // Mock dept breadcrumb path
  const deptCrumb = ext.dept ? deptPath(ext.dept, lang).join(" / ") : "";

  const tabs = [
    { k:"overview",    label: t.detail_overview },
    { k:"setup",       label: t.detail_setup },
    { k:"permissions", label: t.detail_permissions },
    { k:"reviews",     label: t.detail_reviews + ` (${meta.reviews.length})` },
