// @vitest-environment happy-dom
import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { render, screen, waitFor, cleanup } from "@testing-library/react";
import userEvent from "@testing-library/user-event";

import { InstallButton } from "./install-button";

vi.mock("next-intl", () => ({
  useTranslations: () => (key: string) => key,
}));

const mockPush = vi.fn();
vi.mock("@/lib/i18n/navigation", () => ({
  useRouter: () => ({ push: mockPush, replace: vi.fn() }),
}));

vi.mock("@/lib/actions/install", () => ({
  installExtension: vi.fn(),
}));

import { installExtension } from "@/lib/actions/install";

afterEach(cleanup);
beforeEach(() => {
  vi.clearAllMocks();
});

describe("InstallButton", () => {
  it("renders with install label by default", () => {
    render(<InstallButton extensionId="ext-1" />);
    expect(screen.getByRole("button", { name: /install/ })).toBeInTheDocument();
  });

  it("calls installExtension with the extensionId when clicked", async () => {
    vi.mocked(installExtension).mockResolvedValue({
      ok: true,
      installId: "i1",
      isFirstInstall: true,
      version: "1.0.0",
    });
    const user = userEvent.setup();

    render(<InstallButton extensionId="ext-42" />);
    await user.click(screen.getByRole("button", { name: /install/ }));

    await waitFor(() => expect(installExtension).toHaveBeenCalledWith("ext-42"));
  });

  it("shows 'installed' label after a successful install", async () => {
    vi.mocked(installExtension).mockResolvedValue({
      ok: true,
      installId: "i1",
      isFirstInstall: true,
      version: "1.0.0",
    });
    const user = userEvent.setup();

    render(<InstallButton extensionId="ext-1" />);
    await user.click(screen.getByRole("button"));

    await waitFor(() =>
      expect(screen.getByRole("button", { name: /installed/ })).toBeInTheDocument(),
    );
  });

  it("redirects to /sign-in when the user is unauthenticated", async () => {
    vi.mocked(installExtension).mockResolvedValue({ ok: false, error: "unauthenticated" });
    const user = userEvent.setup();

    render(<InstallButton extensionId="ext-1" />);
    await user.click(screen.getByRole("button", { name: /install/ }));

    await waitFor(() => expect(mockPush).toHaveBeenCalledWith("/sign-in"));
  });

  it("renders the large size variant", () => {
    render(<InstallButton extensionId="ext-1" size="lg" />);
    const btn = screen.getByRole("button", { name: /install/ });
    expect(btn.className).toContain("px-4");
  });
});

import { sql } from "drizzle-orm";
import {
  bigint,
  customType,
  index,
  integer,
  jsonb,
  numeric,
  pgEnum,
  pgTable,
  primaryKey,
  text,
  timestamp,
  unique,
} from "drizzle-orm/pg-core";

import { users } from "./auth";
import { departments, organizations } from "./org";

// tsvector is a Postgres-native type; Drizzle doesn't ship a built-in helper.
// We declare it as a custom type so the ORM can reference it in WHERE clauses
// via sql``. It is GENERATED ALWAYS (read-only); never written by app code.
const tsvector = customType<{ data: string }>({
  dataType() { return "tsvector"; },
});

export const extensionCategoryEnum = pgEnum("extension_category", [
  "skills",
  "mcp",
  "slash",
  "plugins",
]);

export const extensionScopeEnum = pgEnum("extension_scope", [
  "personal",
  "org",
  "enterprise",
]);

export const extensionBadgeEnum = pgEnum("extension_badge", [
  "official",
  "popular",
  "new",
]);

export const funcCatEnum = pgEnum("func_cat", [
  "workTask",
  "business",
  "tools",
]);

export const visibilityEnum = pgEnum("extension_visibility", [
  "draft",
  "published",
  "archived",
]);

export const versionStatusEnum = pgEnum("version_status", [
  "pending",
  "scanning",
  "ready",
  "rejected",
]);

export const fileScanStatusEnum = pgEnum("file_scan_status", [
  "pending",
  "clean",
  "flagged",
]);

export const extensions = pgTable(
  "extensions",
  {
    id: text().primaryKey(),
    slug: text().notNull().unique(),
    category: extensionCategoryEnum().notNull(),
    badge: extensionBadgeEnum(),
    scope: extensionScopeEnum().notNull(),
    funcCat: funcCatEnum().notNull(),
    subCat: text().notNull(),
    l2: text(),
    publisherUserId: text().references(() => users.id, {
      onDelete: "set null",
    }),
    ownerOrgId: text()

);

export const files = pgTable("files", {
  id: text().primaryKey(),
  extensionVersionId: text().references(() => extensionVersions.id, {
    onDelete: "set null",
  }),
  r2Key: text().notNull(),
  size: bigint({ mode: "bigint" }).notNull(),
  checksumSha256: text().notNull(),
  mimeType: text(),
  scanStatus: fileScanStatusEnum().notNull().default("pending"),
  scanReport: jsonb(),
  createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
});

export const tags = pgTable("tags", {
  id: text().primaryKey(), // tag key, e.g. "real-time"
  labelEn: text().notNull(),
  labelZh: text().notNull(),
});

export const extensionTags = pgTable(
  "extension_tags",
  {
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    tagId: text()
      .notNull()
      .references(() => tags.id, { onDelete: "cascade" }),
  },
  (t) => [
    primaryKey({ columns: [t.extensionId, t.tagId] }),
    index("idx_extension_tags_tag_ext").on(t.tagId, t.extensionId),
  ],
);

