// @vitest-environment happy-dom
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { cleanup, render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";

import { InstallCommand } from "./install-command";

const writeText = vi.fn().mockResolvedValue(undefined);

beforeEach(() => {
  writeText.mockClear();
  Object.assign(navigator, { clipboard: { writeText } });
});
afterEach(cleanup);

describe("InstallCommand", () => {
  it("renders the command with a $ prompt", () => {
    render(
      <InstallCommand
        command="agentcenter install foo"
        copyLabel="Copy"
        copiedLabel="Copied"
      />,
    );
    expect(screen.getByText("agentcenter install foo")).toBeInTheDocument();
    expect(screen.getByText("$")).toBeInTheDocument();
  });

  it("writes the command to the clipboard when Copy is clicked", async () => {
    const user = userEvent.setup();
    render(
      <InstallCommand
        command="agentcenter install foo"
        copyLabel="Copy"
        copiedLabel="Copied"
      />,
    );

    await user.click(screen.getByRole("button", { name: "Copy" }));

    expect(writeText).toHaveBeenCalledWith("agentcenter install foo");
  });

  it("flips the button label to Copied after a successful copy", async () => {
    const user = userEvent.setup();
    render(
      <InstallCommand
        command="agentcenter install foo"
        copyLabel="Copy"
        copiedLabel="Copied"
      />,
    );

    await user.click(screen.getByRole("button", { name: "Copy" }));

    await waitFor(() =>
      expect(
        screen.getByRole("button", { name: /Copied/ }),
      ).toBeInTheDocument(),
    );
  });
});

