/**
 * Returns the URL only when it parses and uses an http(s) scheme.
 * Use for any href whose value comes from extension manifests / user input,
 * to keep `javascript:`, `data:`, etc. out of the rendered DOM.
 */
export function safeExternalUrl(value: string | null | undefined): string | null {
  if (!value) return null;
  try {
    const url = new URL(value);
    return url.protocol === "http:" || url.protocol === "https:"
      ? url.toString()
      : null;
  } catch {
    return null;
  }
}

