import { SearchX } from "lucide-react";

import type { ExtensionListItem } from "@/lib/db/queries/extensions";
import type { Locale } from "@/types";

import { ExtCard } from "./ext-card";

interface ExtGridProps {
  items: ExtensionListItem[];
  locale?: Locale;
  query?: string;
}

export function ExtGrid({ items, locale = "en", query }: ExtGridProps) {
  if (items.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center gap-3 py-20 text-center">
        <SearchX className="h-10 w-10 text-muted-foreground/40" />
        {query ? (
          <>
            <p className="text-sm font-medium text-foreground">No results for &ldquo;{query}&rdquo;</p>
            <p className="text-xs text-muted-foreground">Try adjusting your search or clearing some filters.</p>
          </>
        ) : (
          <p className="text-sm text-muted-foreground">No extensions found. Try adjusting the filters.</p>
        )}
      </div>
    );
  }
  return (
    <div className="grid grid-cols-[repeat(auto-fill,minmax(280px,1fr))] gap-4">
      {items.map((ext) => (
        <ExtCard key={ext.id} ext={ext} locale={locale} />
      ))}
    </div>
  );
}

import { getTranslations } from "next-intl/server";

import { ExtGrid } from "@/components/extension/ext-grid";
import { FilterBar } from "@/components/filters/filter-bar";
import { getSession } from "@/lib/auth/session";
import {
  countFilteredExtensions,
  listExtensions,
} from "@/lib/db/queries/extensions";
import { getTagsWithCounts } from "@/lib/db/queries/tags";
import { parseFilters } from "@/lib/validators/filters";
import type { Locale } from "@/types";

export default async function ExtensionsPage({
  params,
  searchParams,
}: {
  params: Promise<{ locale: string }>;
  searchParams: Promise<Record<string, string | string[] | undefined>>;
}) {
  const [{ locale }, rawParams, session] = await Promise.all([
    params,
    searchParams,
    getSession(),
  ]);
  const t = await getTranslations("extensions");
  const filters = parseFilters(rawParams);
  const userDeptId = session?.user.defaultDeptId ?? undefined;

  const [items, total, tags] = await Promise.all([
    listExtensions(filters, userDeptId),
    countFilteredExtensions(filters, userDeptId),
    getTagsWithCounts(),
  ]);

  return (
    <div className="px-7 py-5">
      <header className="mb-5 flex items-baseline gap-3">
        <h1 className="serif text-2xl tracking-tight">{t("browseTitle")}</h1>
        <span className="text-muted-foreground text-[13px]">
          {t("count", { count: total })}
        </span>
      </header>

      <FilterBar tags={tags} />

      <ExtGrid items={items} locale={locale as Locale} query={filters.q} />
    </div>
  );
}

